<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">  --disaggregation-mode</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> decode</span><span style="--shiki-light:#EE0000;--shiki-dark:#D7BA7D;"> \\</span></span>
